impl Solution { pub fn max_removals(source: String, pattern: String, target_indices: Vec<i32>) -> i32 { let (s, p) = (source.as_bytes(), pattern.as_bytes()); let (n, m) = (s.len(), p.len()); let mut is_black_target = vec![false; n]; for &i in &target_indices { is_black_target[i as usize] = true; } let mut black_dp = vec![vec![-1000000; m + 1]; n + 1]; black_dp[0][0] = 0; for i in 0..n { for j in 0..=m { if black_dp[i][j] < 0 { continue; } black_dp[i+1][j] = black_dp[i+1][j].max(black_dp[i][j] + is_black_target[i] as i32); if j < m && s[i] == p[j] { black_dp[i+1][j+1] = black_dp[i+1][j+1].max(black_dp[i][j]); } } } black_dp[n][m] } }